    try {
        await pb.collection('_superusers').authWithPassword(
            process.env.PB_ADMIN_EMAIL,
            process.env.PB_ADMIN_PASSWORD
        );

        const orders = await pb.collection('orders').getFullList();
        console.log(`Total Orders: ${orders.length}`);
        for (const order of orders) {
            console.log(`Order ID: ${order.id}, Customer: ${order.customer}`);
            const items = await pb.collection('order_items').getFullList({
                filter: `order = "${order.id}"`
            });
            console.log(`  Items referencing this order (${items.length}):`);
            for (const item of items) {
                console.log(`    Item ID: ${item.id}, Product: ${item.product}, Quantity: ${item.quantity}`);
            }
        }
    } catch (err) {
        console.error('Error:', err);
    }
}

main();

